```class Solution {
public:
    int getKth(int lo, int hi, int k) {
        int power[hi - lo + 1];
        int result = -1;
        for (int i = lo; i <= hi; i++) {
            power[i] = calculatePower(i);
        }
        int j = 0;
        for (int i = lo; i <= hi; i++) {
            if (j < k && power[i] == power[j]) {
                result = i;
                j++;
            }
        }
        return result;
    }

    int calculatePower(int num) {
        int result = num;
        while (num != 1) {
            if (num % 2 == 0) {
                result /= 2;
            } else {
                result = (result * 3) + 1;
            }
            num = num / 2;
        }
        return result;
    }
};
```

